#include <iostream>
#include <string>
#include <algorithm>
#include <cctype>

bool isPalindrome(const std::string& s) {
    std::string filtered_s;
    filtered_s.reserve(s.length());

    for (char c : s) {
        if (!std::isspace(static_cast<unsigned char>(c))) {
            filtered_s += std::tolower(static_cast<unsigned char>(c));
        }
    }

    if (filtered_s.empty()) {
        return true;
    }

    int left = 0;
    int right = filtered_s.length() - 1;

    while (left < right) {
        if (filtered_s[left] != filtered_s[right]) {
            return false;
        }
        left++;
        right--;
    }

    return true;
}

int main() {
    std::string input;
    while (std::getline(std::cin, input)) {
        if (input == "__END_OF_INPUT__") break;
        std::cout << (isPalindrome(input) ? "true" : "false") << std::endl;
    }
    return 0;
}
